     1→import { useEffect, useRef, useState } from "react";
     2→
     3→interface UseCameraResult {
     4→  videoRef: React.RefObject<HTMLVideoElement | null>;
     5→  isReady: boolean;
     6→  error: string | null;
     7→}
     8→
     9→export function useCamera(): UseCameraResult {
    10→  const videoRef = useRef<HTMLVideoElement | null>(null);
    11→  const [isReady, setIsReady] = useState(false);
    12→  const [error, setError] = useState<string | null>(null);
    13→  const streamRef = useRef<MediaStream | null>(null);
    14→
    15→  useEffect(() => {
    16→    let cancelled = false;
    17→
    18→    async function startCamera() {
    19→      try {
    20→        const stream = await navigator.mediaDevices.getUserMedia({
    21→          video: { facingMode: "user", width: 1280, height: 720 },
    22→          audio: false,
    23→        });
    24→
    25→        if (cancelled) {
    26→          stream.getTracks().forEach((t) => t.stop());
    27→          return;
    28→        }
    29→
    30→        streamRef.current = stream;
    31→
    32→        if (videoRef.current) {
    33→          videoRef.current.srcObject = stream;
    34→          await videoRef.current.play();
    35→          setIsReady(true);
    36→        }
    37→      } catch (err) {
    38→        if (!cancelled) {
    39→          setError(err instanceof Error ? err.message : "Camera access denied");
    40→        }
    41→      }
    42→    }
    43→
    44→    startCamera();
    45→
    46→    return () => {
    47→      cancelled = true;
    48→      streamRef.current?.getTracks().forEach((t) => t.stop());
    49→      streamRef.current = null;
    50→      setIsReady(false);
    51→    };
    52→  }, []);
    53→
    54→  return { videoRef, isReady, error };
    55→}
    56→

