    65→
    66→  // Accumulate full response text before deciding delivery method
    67→  const responseAccumulatorRef = useRef<string>("");
    68→
    69→  // Stash remaining text after a scripted video; drained when video ends
    70→  const pendingTTSAfterScriptedRef = useRef<string | null>(null);
    71→
    72→  // Sentence buffer: used for non-scripted responses (TTS path)
    73→  const sentenceBuffer = useMemo(
    74→    () =>
    75→      new SentenceBuffer((sentence) => {
    76→        avatar.speak(sentence);
    77→      }),
    78→    // eslint-disable-next-line react-hooks/exhaustive-deps
    79→    [avatar.speak],
