    95→    socket.connect();
    96→
    97→    if (userId) {
    98→      socket.emit("join_room", { user_id: userId });
    99→    }
   100→
   101→    return () => {
   102→      socket.disconnect();
   103→    };
   104→  }, [userId]);
   105→
   106→  // Listen for session_active from backend
   107→  useEffect(() => {
   108→    const handleSessionActive = () => {
   109→      setSessionActive(true);
   110→      setIsStarting(false);
   111→      setCanvasOutfits([]);
   112→      setCanvasOutfitIndex(0);
   113→      avatar.startSession();
   114→      stt.startListening();
   115→    };
