   123→
   124→  // Listen for mira_speech events (streamed text from AI)
   125→  useEffect(() => {
   126→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
   127→      // Fallback session detection
   128→      if (!sessionActive && !isStarting) {
   129→        setSessionActive(true);
   130→        setIsStarting(false);
   131→        avatar.startSession();
   132→        stt.startListening();
   133→      }
   134→
   135→      if (data.is_chunk !== false) {
   136→        // Still accumulating — skip empty chunks
   137→        if (!data.text) return;
   138→        console.log("[Mirror] mira_speech chunk received");
   139→        responseAccumulatorRef.current += data.text;
   140→        avatar.setAvatarState("thinking");
   141→      } else {
   142→        // New complete message arrived — discard any stale pending TTS
   143→        pendingTTSAfterScriptedRef.current = null;
   144→        // End of message — accumulate any final text, then deliver
   145→        if (data.text) {
   146→          responseAccumulatorRef.current += data.text;
   147→        }
   148→        const fullText = responseAccumulatorRef.current;
   149→        responseAccumulatorRef.current = "";
   150→        console.log("[Mirror] Agent full response:", fullText);
   151→        if (!fullText) return;
   152→
   153→        // Check for scripted response match
   154→        const scripted = findScriptedResponse(fullText);
   155→
   156→        if (scripted) {
   157→          // Play pre-recorded video, then TTS any remaining text
   158→          console.log("[Mirror] Scripted match:", scripted.phrase);
   159→          const phraseIdx = fullText.toLowerCase().indexOf(scripted.phrase);
   160→          const afterPhrase = phraseIdx >= 0
   161→            ? fullText.slice(phraseIdx + scripted.phrase.length).trim()
   162→            : "";
   163→          if (afterPhrase) {
   164→            pendingTTSAfterScriptedRef.current = afterPhrase;
   165→            console.log("[Mirror] Pending TTS after scripted:", afterPhrase.slice(0, 80));
   166→          }
   167→          avatar.playScripted(scripted.video);
   168→        } else {
   169→          // No match — detect emotion for avatar state, then TTS per sentence
   170→          const emotion = detectEmotion(fullText);
   171→          avatar.setAvatarState(emotion);
   172→
   173→          // Feed full text through sentence buffer for per-sentence TTS
   174→          sentenceBuffer.feed(fullText);
