   177→      }
   178→    };
   179→
   180→    socket.on("mira_speech", handleSpeech);
   181→    return () => {
   182→      socket.off("mira_speech", handleSpeech);
   183→    };
   184→    // eslint-disable-next-line react-hooks/exhaustive-deps
   185→  }, [sessionActive, isStarting, sentenceBuffer]);
