    28→/** Parse [emotion:X] prefix tag from Claude's response. */
    29→export function parseEmotionTag(text: string): {
    30→  emotion: MiraEmotion;
    31→  cleanText: string;
    32→} {
    33→  const match = text.match(/^\[emotion:(\w+)\]\s*/);
    34→  if (match) {
    35→    const tag = match[1] as MiraEmotion;
    36→    const validEmotions: MiraEmotion[] = ["idle", "neutral", "proud", "teasing"];
    37→    return {
    38→      emotion: validEmotions.includes(tag) ? tag : "neutral",
    39→      cleanText: text.slice(match[0].length),
    40→    };
    41→  }
    42→  return { emotion: "neutral", cleanText: text };
    43→}
