PHOTO_TIMEOUT_SECONDS = 5

async def _take_photo(self, user_id: str, reason: str) -> dict:
    """Request a photo from the mirror and wait for the response.

    Returns a dict with either the image data or an error.
    The result is formatted for direct use as a multimodal tool result.
    """
    if not self.sio:
        return {"error": "Socket.io not available"}

    # Create a Future that the photo_response handler will resolve
    loop = asyncio.get_running_loop()
    future: asyncio.Future[str] = loop.create_future()
    self._pending_photos[user_id] = future

    # Request the photo from the frontend
    print(f"[mira] Requesting photo from mirror for {user_id} (reason: {reason})")
    await self.sio.emit("request_photo", {"user_id": user_id}, room=user_id)

