                        "text": f"Photo captured ({photo_result['reason']}). Here is what the user looks like right now:",
                    },
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/jpeg",
                            "data": photo_result["image_base64"],
                        },
                    },
                ],
            }
        tool_results.append(tool_result_block)
    else:
        # Standard tool execution path (unchanged)
        try:
            result = await execute_tool(
                tool_name=tool_use.name,
                tool_input=tool_use.input,
                user_context={
                    "user_id": session.user_id,
                    "session_id": session.session_id,
                    "oauth_token": session.user_context.get("oauth_token"),
                },
            )
        except Exception as e:
            print(f"[mira] Tool {tool_use.name} failed: {e}")
            result = {"error": f"Tool execution failed: {str(e)}"}

        # Parallel broadcast: send results to frontend via Socket.io
        frontend_payload = result.pop("frontend_payload", None)
        if frontend_payload and self.sio:
            await self.sio.emit(
                "tool_result",
                frontend_payload,
                room=session.user_id,
            )

        # Cache voice messages for session history
        if tool_use.name == "send_voice_to_client" and result.get("text"):
            session.voice_messages.append({
                "text": result["text"],
                "emotion": result.get("emotion", "neutral"),
                "timestamp": time.time(),
            })

        # Track items shown
        if tool_use.name in ("present_items", "display_product") and result.get("items"):
            session.items_shown += len(result["items"])
            if result["items"]:
                session._last_shown_item = result["items"][0]

        tool_result_block = {
            "type": "tool_result",
            "tool_use_id": tool_use.id,
            "content": json.dumps(result),
        }
        if "error" in result:
            tool_result_block["is_error"] = True
        tool_results.append(tool_result_block)
```

#### E. Update `_select_model` (minor)

The model selector should recognize that when the last message contains a `take_photo` tool result, it should use Sonnet (not Haiku) because Claude needs to analyze an image and provide a verbal reaction -- quality matters more than speed here. However, the current logic already uses Sonnet for the initial tool call turn and Haiku for tool result processing. For `take_photo`, image analysis quality is important, so we should ensure Sonnet is used when the tool result contains an image.

Add to `_select_model` before the Haiku return:

```python
# Use Sonnet when processing image-containing tool results (take_photo)
if last_msg.get("role") == "user" and isinstance(last_msg.get("content"), list):
    for block in last_msg["content"]:
        if isinstance(block, dict) and block.get("type") == "tool_result":
            content = block.get("content")
            if isinstance(content, list) and any(
                isinstance(c, dict) and c.get("type") == "image" for c in content
            ):
                return SONNET_MODEL, 400
```

Place this check BEFORE the existing Haiku check at lines 258-264 so it takes priority.

---

### File 3: `backend/main.py`

**Add a new `photo_response` Socket.io event handler** after the `mirror_event` handler (around line 217):

```python
@sio.event
async def photo_response(sid, data):
    """Handle photo responses from the mirror (bypasses handle_event to avoid deadlock).

    Expected data: {
        "user_id": "uuid",
        "image_base64": "base64-encoded JPEG"
    }
    """
    user_id = data.get("user_id")
    image_base64 = data.get("image_base64")

    if not user_id or not image_base64:
        print(f"[socket] photo_response: missing user_id or image_base64 from {sid}")
        return

    print(f"[socket] photo_response from {user_id} ({len(image_base64)} bytes)")
    resolved = mira.resolve_photo(user_id, image_base64)
    if not resolved:
        print(f"[socket] photo_response: no pending photo request for {user_id}")
```

This handler is deliberately simple. It does NOT touch `handle_event`, does NOT modify `conversation_history`, and does NOT interact with `is_processing`. It simply resolves the Future that the `_take_photo` method is awaiting.

---

### File 4: `frontend/src/app/mirror/page.tsx`

**Add a `request_photo` listener** inside a new `useEffect` block. Place it immediately after the existing `request_snapshot` listener (after line 290):

```typescript
// Listen for photo requests from the backend (tool-invoked, separate from session-start snapshot)
useEffect(() => {
  const handlePhotoRequest = () => {
    const video = videoRef.current;
    if (!video || video.readyState < video.HAVE_CURRENT_DATA) {
      // Camera not ready — emit an empty response so the backend times out gracefully
      // rather than hanging for the full timeout
      console.warn("[Mirror] Photo requested but camera not ready");
      return;
    }

    const canvas = document.createElement("canvas");
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    ctx.drawImage(video, 0, 0);
    const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
    const base64 = dataUrl.split(",")[1];

    // Send via dedicated photo_response event (NOT mirror_event)
    // This bypasses the orchestrator's handle_event to avoid deadlock
    socket.emit("photo_response", {
      user_id: userId,
      image_base64: base64,
    });
  };

  socket.on("request_photo", handlePhotoRequest);
  return () => {
    socket.off("request_photo", handlePhotoRequest);
  };
}, [videoRef, userId]);
```

**Optional fix for existing snapshot bug**: Also fix the existing `handleSnapshotRequest` to use the correct nested `event` structure so the session-start snapshot actually works:

```typescript
// Change line 279-283 from:
socket.emit("mirror_event", {
  type: "snapshot",
  image_base64: base64,
  user_id: userId,
});

// To:
socket.emit("mirror_event", {
  user_id: userId,
  event: {
    type: "snapshot",
    image_base64: base64,
  },
});
```

---

### Edge Cases and Error Handling

1. **Timeout (camera not ready / frontend disconnected)**: The `asyncio.wait_for` with `PHOTO_TIMEOUT_SECONDS = 5` ensures the tool handler never blocks indefinitely. The error message tells Claude the camera may not be ready, so it can tell the user naturally.

2. **Multiple concurrent `take_photo` calls for same user**: Only one Future per `user_id` is stored. If Claude somehow issues two `take_photo` calls in the same tool batch (unlikely given it requires a `reason`), the second would overwrite the first's Future. The `_pending_photos` cleanup in the `finally` block prevents stale Futures.

3. **Session ends while waiting for photo**: The Future would timeout (5 seconds). The `finally` block cleans up. No orphaned Futures.

4. **Frontend sends `photo_response` with no pending request**: `resolve_photo` returns `False` and logs a warning. No crash.

5. **Image too large**: JPEG at 0.7 quality from a typical webcam is 50-200KB base64. Anthropic's API supports up to 20MB per image. No concern.

6. **Model selection for image analysis**: The `_select_model` modification ensures Sonnet (not Haiku) processes the image, giving higher quality visual analysis and outfit commentary.

---

### Sequence Diagram

```
Claude (tool_use: take_photo)
    |
    v
orchestrator._handle_tool_calls()
    |-- intercepts "take_photo"
    |-- calls _take_photo(user_id, reason)
    |     |-- creates asyncio.Future
    |     |-- stores in _pending_photos[user_id]
    |     |-- emits "request_photo" via Socket.io
    |     |-- awaits Future (max 5s)
    |     |
    |     |   [meanwhile, on the frontend:]
    |     |   mirror/page.tsx receives "request_photo"
    |     |   captures video frame -> JPEG base64
    |     |   emits "photo_response" with {user_id, image_base64}
    |     |
    |     |   [meanwhile, on the backend:]
    |     |   main.py "photo_response" handler fires
    |     |   calls mira.resolve_photo(user_id, image_base64)
    |     |   Future.set_result(image_base64) <-- unblocks _take_photo
    |     |
    |     |-- Future resolves with image_base64
    |     |-- returns {success, reason, image_base64}
    |
    |-- builds multimodal tool_result with image block
    |-- appends to conversation_history
    |-- calls _call_claude() recursively (tool_depth + 1)
    |
    v
Claude sees the image, reacts to the user's outfit
```

---

### Testing Considerations

1. **Unit test for `_take_photo` timeout**: Create a `MiraOrchestrator` with a mock Socket.io, call `_take_photo`, never resolve the Future, assert it returns the timeout error within ~5 seconds.

2. **Unit test for `resolve_photo` happy path**: Create a Future, store it in `_pending_photos`, call `resolve_photo`, assert it returns True and the Future's result matches.

3. **Unit test for `resolve_photo` with no pending request**: Call `resolve_photo` when `_pending_photos` is empty, assert it returns False.

4. **Integration test for `_handle_tool_calls` with `take_photo`**: Mock a tool_use block with `name="take_photo"`, mock `_take_photo` to return an image, assert the tool_result_block has multimodal content with image type.

5. **Frontend test**: Mock `socket.on("request_photo")`, verify it captures from the video element and emits `photo_response`.

